#!/usr/bin/env node
// Extract memory values from an ELF binary.
// Loads every PT_LOAD segment into a virtual memory image and emits each
// 4-byte aligned little-endian word as an integer keyed by its memory address.
// The lowest loadable virtual address is normalized to the classic x86-64
// load base 0x400000 (matters for PIE binaries whose min vaddr is 0).

'use strict';
const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <binary>\n');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// --- ELF header ---
if (buf.length < 64 || buf.readUInt32LE(0) !== 0x464c457f) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}
const ei_class = buf[4]; // 1=32, 2=64
const is64 = ei_class === 2;

let e_phoff, e_phentsize, e_phnum;
if (is64) {
  e_phoff = Number(buf.readBigUInt64LE(32));
  e_phentsize = buf.readUInt16LE(54);
  e_phnum = buf.readUInt16LE(56);
} else {
  e_phoff = buf.readUInt32LE(28);
  e_phentsize = buf.readUInt16LE(42);
  e_phnum = buf.readUInt16LE(44);
}

const PT_LOAD = 1;
const loads = [];
let minVaddr = null;

for (let i = 0; i < e_phnum; i++) {
  const off = e_phoff + i * e_phentsize;
  const p_type = buf.readUInt32LE(off);
  if (p_type !== PT_LOAD) continue;
  let p_offset, p_vaddr, p_filesz, p_memsz;
  if (is64) {
    p_offset = Number(buf.readBigUInt64LE(off + 8));
    p_vaddr = Number(buf.readBigUInt64LE(off + 16));
    p_filesz = Number(buf.readBigUInt64LE(off + 32));
    p_memsz = Number(buf.readBigUInt64LE(off + 40));
  } else {
    p_offset = buf.readUInt32LE(off + 4);
    p_vaddr = buf.readUInt32LE(off + 8);
    p_filesz = buf.readUInt32LE(off + 16);
    p_memsz = buf.readUInt32LE(off + 20);
  }
  if (p_memsz === 0) continue;
  loads.push({ p_offset, p_vaddr, p_filesz, p_memsz });
  if (minVaddr === null || p_vaddr < minVaddr) minVaddr = p_vaddr;
}

// Normalize lowest loadable address to 0x400000.
const BASE = 0x400000;
const rebase = BASE - (minVaddr === null ? 0 : minVaddr);

const out = {};
for (const seg of loads) {
  const memAddr = seg.p_vaddr + rebase;
  // iterate 4-byte aligned words within [p_vaddr, p_vaddr + p_memsz)
  for (let o = 0; o + 4 <= seg.p_memsz; o += 4) {
    let val;
    if (o + 4 <= seg.p_filesz) {
      val = buf.readUInt32LE(seg.p_offset + o);
    } else if (o >= seg.p_filesz) {
      val = 0; // bss / zero-filled tail
    } else {
      // straddles file/zero boundary
      let v = 0;
      for (let b = 0; b < 4; b++) {
        const fo = o + b;
        const byte = fo < seg.p_filesz ? buf[seg.p_offset + fo] : 0;
        v |= byte << (8 * b);
      }
      val = v >>> 0;
    }
    out[memAddr + o] = val;
  }
}

process.stdout.write(JSON.stringify(out));

